  async setOAppConfig(rpc, delegate, params, commitment = "confirmed") {
    const { oapp, eid, config: config2, msgLibProgram } = params;
    const [msgLib] = new MessageLibPDA(msgLibProgram).messageLib();
    const msgLibVersion = params.msgLibVersion ?? await this.getMessageLibVersion(rpc, delegate.publicKey, msgLibProgram, commitment);
    let msgLibClient;
    if (msgLibVersion.major === 0n && msgLibVersion.minor == 0 && msgLibVersion.endpointVersion == 2) {
      msgLibClient = new simple_message_lib_exports.SimpleMessageLib(msgLibProgram);
    } else if (msgLibVersion.major === 3n && msgLibVersion.minor == 0 && msgLibVersion.endpointVersion == 2) {
      msgLibClient = new uln_exports.Uln(msgLibProgram);
    } else {
      throw new Error(
        `unsupported message lib version ${msgLibVersion.major.toString()}.${msgLibVersion.minor.toString()}`
      );
    }
    const txBuilder = setConfig(
      { programs: this.programRepo },
      {
        signer: delegate,
        messageLibInfo: this.pda.messageLibraryInfo(msgLib),
        messageLib: msgLib,
        messageLibProgram: msgLibProgram,
        oappRegistry: this.pda.oappRegistry(oapp),
        // param
        eid,
        configType: config2.configType,
        config: msgLibProgram === SIMPLE_MESSAGELIB_PROGRAM_ID ? new Uint8Array(10).fill(0) : uln_exports.Uln.constructSetConfigData(config2.configType, config2.value),
        oapp
      }
    );
    return txBuilder.addRemainingAccounts(msgLibClient.getSetConfigIXAccountMetaForCPI(oapp, eid)).items[0];
  }
